test('KinesisEventDefinition normalizes the {arn} form', t => {
  const def = new KinesisEventDefinition(
    {arn: 'arn:aws:kinesis:eu-west-1:000000000000:stream/polls'},
    'eu-west-1',
    '000000000000'
  );
  t.is(def.streamName, 'polls');
