const {Writable} = require('stream');
const {spawn} = require('child_process');
const onExit = require('signal-exit');
const {SQS} = require('aws-sdk');
const {chunk} = require('lodash/fp');
const pump = require('pump');
const {getSplitLinesTransform} = require('./utils');

const EXPECTED_LAMBDA_CALLS = 5;
const TIMEOUT_MS = 90000;

const client = new SQS({
  region: 'eu-west-1',
  accessKeyId: 'local',
  secretAccessKey: 'local',
  endpoint: 'http://localhost:9324'
});

const sendMessages = () => {
  return Promise.all([
    client
      .sendMessage({
        QueueUrl: 'http://localhost:9324/queue/MyFirstQueue',
        MessageBody: 'MyFirstMessage',
        MessageAttributes: {
          myAttribute: {DataType: 'String', StringValue: 'myAttribute'}
        }
      })
      .promise(),
    client
      .sendMessage({
        QueueUrl: 'http://localhost:9324/queue/MySecondQueue',
        MessageBody: 'MySecondMessage'
      })
      .promise(),
    client
      .sendMessage({
        QueueUrl: 'http://localhost:9324/queue/MyThirdQueue',
        MessageBody: 'MyThirdMessage'
      })
      .promise(),
    client
      .sendMessage({
        QueueUrl: 'http://localhost:9324/queue/MyFourthQueue',
        MessageBody: 'MyFourthMessage'
      })
      .promise(),
    ...chunk(
      10,
      Array.from({length: 70}).map((_, Id) => ({
        Id: `${Id}`,
        MessageBody: 'MyLargestBatchSizeQueue'
      }))
    ).map(Entries =>
      client
        .sendMessageBatch({
          QueueUrl: 'http://localhost:9324/queue/MyLargestBatchSizeQueue',
          Entries
        })
        .promise()
    )
  ]);
};

const serverless = spawn('sls', ['offline', 'start', '--config', 'serverless.sqs.yml'], {
  stdio: ['pipe', 'pipe', 'pipe'],
  cwd: __dirname
});

let count = 0;
let settled = false;

const finish = code => {
  if (settled) return;
  settled = true;
  clearTimeout(timer);
  serverless.kill();
  process.exit(code);
};

const timer = setTimeout(() => {
  console.error(
    `[test-sqs] TIMED OUT after ${TIMEOUT_MS}ms with ${count}/${EXPECTED_LAMBDA_CALLS} lambda calls`
  );
  finish(1);
}, TIMEOUT_MS);

// Surface serverless-offline output so CI failures are diagnosable (the previous
// version swallowed it). Also count lambda invocations and stop once we have enough.
pump(
  serverless.stderr,
  getSplitLinesTransform(),
  new Writable({
    objectMode: true,
    write(line, enc, cb) {
      process.stderr.write(`[sls] ${line}\n`);

      if (/Starting Offline SQS/.test(line)) {
        sendMessages().catch(err => console.error('[test-sqs] sendMessages failed:', err.message));
      }

      count += (
        line.match(/\(λ: .*\) RequestId: .* Duration: .* ms {2}Billed Duration: .* ms/g) || []
      ).length;

      if (count >= EXPECTED_LAMBDA_CALLS) {
        console.log(`[test-sqs] reached ${count}/${EXPECTED_LAMBDA_CALLS} lambda calls`);
        finish(0);
      }

      cb();
    }
  })
);

serverless.on('close', code => {
  if (settled) return;
  console.error(
    `[test-sqs] serverless exited early (code ${code}) with ${count}/${EXPECTED_LAMBDA_CALLS} lambda calls`
  );
  finish(code || 1);
});

onExit((code, signal) => {
  if (signal) serverless.kill(signal);
});

